/* main.min.js — patch portfolio | defer loaded */
(function(){'use strict';
/* Mobile nav */
var T=document.getElementById('navToggle'),L=document.getElementById('navLinks');
T.addEventListener('click',function(){var o=L.classList.toggle('open');T.classList.toggle('open',o);T.setAttribute('aria-expanded',o);});
L.querySelectorAll('a').forEach(function(a){a.addEventListener('click',function(){L.classList.remove('open');T.classList.remove('open');T.setAttribute('aria-expanded','false');});});
/* Nav scroll border — rAF throttled */
var N=document.getElementById('mainNav'),tk=false;
window.addEventListener('scroll',function(){if(!tk){requestAnimationFrame(function(){N.classList.toggle('scrolled',window.scrollY>40);tk=false;});tk=true;}},{passive:true});
/* Custom cursor — fine pointer only */
if(window.matchMedia('(pointer:fine)').matches){
  var C=document.getElementById('cursor'),R=document.getElementById('cursorRing');
  C.style.display='block';R.style.display='block';document.body.style.cursor='none';
  var mx=0,my=0,rx=0,ry=0,rafId,lrx,lry;
  document.addEventListener('mousemove',function(e){mx=e.clientX;my=e.clientY;C.style.transform='translate('+mx+'px,'+my+'px) translate(-50%,-50%)';},{passive:true});
  function ar(){rx+=(mx-rx)*.12;ry+=(my-ry)*.12;if(Math.abs(rx-(lrx||0))>.2||Math.abs(ry-(lry||0))>.2){R.style.transform='translate('+rx+'px,'+ry+'px) translate(-50%,-50%)';lrx=rx;lry=ry;}rafId=requestAnimationFrame(ar);}
  ar();
  document.addEventListener('visibilitychange',function(){if(document.hidden){cancelAnimationFrame(rafId);}else{ar();}});
  document.querySelectorAll('a,button,.skill-card,.project-card,.cert-card').forEach(function(el){el.addEventListener('mouseenter',function(){R.classList.add('hovering');});el.addEventListener('mouseleave',function(){R.classList.remove('hovering');});});
}
/* Scroll reveal — single observer, unobserve after fire */
if('IntersectionObserver' in window){
  var obs=new IntersectionObserver(function(entries){entries.forEach(function(e){if(e.isIntersecting){e.target.classList.add('visible');obs.unobserve(e.target);}});},{threshold:.1,rootMargin:'0px 0px -40px 0px'});
  document.querySelectorAll('.reveal').forEach(function(el){obs.observe(el);});
}else{document.querySelectorAll('.reveal').forEach(function(el){el.classList.add('visible');});}
/* Terminal line fade — CSS animation, no setTimeout */
document.querySelectorAll('.t-line').forEach(function(l,i){l.style.opacity='0';l.style.animation='fadeIn .12s '+(0.9+i*.065)+'s forwards';});
})();
